package workloadmanager

import (
	"context"
	"net/http"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/client-go/informers"
	"k8s.io/client-go/kubernetes"
	listersv1 "k8s.io/client-go/listers/core/v1"
	"k8s.io/client-go/tools/cache"
	"k8s.io/utils/ptr"
)

type Server struct {
	config            *Config
	router            *gin.Engine
	httpServer        *http.Server
	k8sClient         *K8sClient
	sandboxController *SandboxReconciler
	tokenCache        *TokenCache
	informers         *Informers
	storeClient       store.Store
	wg                sync.WaitGroup
}

func NewServer(cfg *Config) (*Server, error) {
	k8sClient, err := NewK8sClient()
	if err != nil {
		return nil, err
	}

	informers, err := NewInformers(k8sClient)
	if err != nil {
		return nil, err
	}

	s := &Server{
		config:      cfg,
		k8sClient:   k8sClient,
		informers:   informers,
		tokenCache:  NewTokenCache(1000, 5*time.Minute),
		storeClient: store.Storage(),
	}

	s.sandboxController = NewSandboxReconciler(s.k8sClient.dynamicClient, s.k8sClient.scheme)
	s.setupRoutes()

	return s, nil
}

func (s *Server) setupRoutes() {
	if s.config.EnableTLS {
		gin.SetMode(gin.ReleaseMode)
	}

	s.router = gin.New()
	s.router.Use(gin.Recovery())

	s.router.GET("/health", s.handleHealth)

	v1 := s.router.Group("/v1")
	{
		agentRuntime := v1.Group("/agent-runtime")
		if s.config.EnableAuth {
